// ============================================================
// telegramAgent.js — AviSignals Telegram Agent v2
//
// Three jobs in one file:
//  1. CHANNEL BROADCASTER  — posts 3x per hour to the public
//     channel with rotating content (sales pitch, success story,
//     signal tease, urgency post, educational, testimonial)
//  2. ADMIN BOT            — answers your questions about the
//     business in real-time via Telegram private chat
//  3. SOCIAL MEDIA SYNC    — shares the daily content calendar
//     generated by socialMediaAgent directly to admin
//
// Improvements over v1:
//  - 3x per hour (was once every 3 hours)
//  - 6 rotating content types — never repeats same format twice in a row
//  - Post history fed back to AI so it never repeats content
//  - Admin bot with polling — you can message it any question
//  - Admin bot has full business context + live Supabase data
//  - Proper byte-length Content-Length (fixes Unicode bugs)
//  - Retry logic on Telegram API failures
//  - Clean HTML formatting for channel posts
// ============================================================

'use strict';

const cron = require('node-cron');
const https = require('https');
const groq = require('./groqClient');
const { createClient } = require('@supabase/supabase-js');

const supabase = createClient(
    process.env.SUPABASE_URL,
    process.env.SUPABASE_SERVICE_ROLE_KEY
);

// ─── Config ───────────────────────────────────────────────────
const BOT_TOKEN = process.env.TELEGRAM_BOT_TOKEN;
const CHANNEL_ID = process.env.TELEGRAM_CHANNEL_ID || '@AviSignalsAviatorPredictorBot';
const ADMIN_CHAT = process.env.TELEGRAM_CHAT_ID;    // your personal Telegram chat ID
const SITE_URL = 'https://avisignals.com';
const BOT_URL = `${SITE_URL}/bot`;

// ─── Post history (in-memory, last 10 posts) ─────────────────
// Fed back to AI so it never repeats the same content
const postHistory = [];
const MAX_HISTORY = 10;

function addToHistory(type, preview) {
    postHistory.push({ type, preview: preview.slice(0, 80), at: new Date().toLocaleTimeString() });
    if (postHistory.length > MAX_HISTORY) postHistory.shift();
}

// ─── Content type rotation ────────────────────────────────────
// Cycles through 6 types so every 2 hours covers all of them
const CONTENT_TYPES = [
    'sales_pitch',
    'success_story',
    'signal_tease',
    'urgency',
    'educational',
    'testimonial'
];
let contentTypeIndex = 0;

function nextContentType() {
    const type = CONTENT_TYPES[contentTypeIndex % CONTENT_TYPES.length];
    contentTypeIndex++;
    return type;
}

// ============================================================
// TELEGRAM API WRAPPER
// ============================================================

function telegramRequest(method, payload, retries = 3) {
    return new Promise((resolve, reject) => {
        if (!BOT_TOKEN) {
            console.warn('⚠️  TELEGRAM_BOT_TOKEN not set');
            return resolve(null);
        }

        const body = JSON.stringify(payload);
        const bodyBuf = Buffer.from(body, 'utf8');

        const options = {
            hostname: 'api.telegram.org',
            path: `/bot${BOT_TOKEN}/${method}`,
            method: 'POST',
            headers: {
                'Content-Type': 'application/json',
                'Content-Length': bodyBuf.length
            }
        };

        const req = https.request(options, (res) => {
            let raw = '';
            res.on('data', chunk => raw += chunk);
            res.on('end', () => {
                try {
                    const parsed = JSON.parse(raw);
                    if (!parsed.ok && retries > 0) {
                        // Telegram rate limit
                        if (parsed.error_code === 429) {
                            const wait = (parsed.parameters?.retry_after || 5) * 1000;
                            console.warn(`⏳ Telegram rate limit — retrying in ${wait}ms`);
                            setTimeout(() => telegramRequest(method, payload, retries - 1).then(resolve).catch(reject), wait);
                        } else {
                            console.error(`❌ Telegram API error [${method}]:`, parsed.description);
                            resolve(parsed);
                        }
                    } else {
                        resolve(parsed);
                    }
                } catch (_) { resolve(null); }
            });
        });

        req.on('error', (e) => {
            console.error(`❌ Telegram request error [${method}]:`, e.message);
            if (retries > 0) {
                setTimeout(() => telegramRequest(method, payload, retries - 1).then(resolve).catch(reject), 2000);
            } else {
                resolve(null);
            }
        });

        req.write(bodyBuf);
        req.end();
    });
}

function sendToChannel(text) {
    return telegramRequest('sendMessage', {
        chat_id: CHANNEL_ID,
        text,
        parse_mode: 'HTML',
        link_preview_options: { is_disabled: true }
    });
}

function sendToAdmin(text) {
    if (!ADMIN_CHAT) {
        console.warn('⚠️  TELEGRAM_CHAT_ID not set — cannot message admin');
        return Promise.resolve(null);
    }
    return telegramRequest('sendMessage', {
        chat_id: ADMIN_CHAT,
        text,
        parse_mode: 'Markdown',
        link_preview_options: { is_disabled: true }
    });
}

