// ─── Route to correct generator ──────────────────────────────
const GENERATORS = {
    sales_pitch: generateSalesPitch,
    success_story: generateSuccessStory,
    signal_tease: generateSignalTease,
    urgency: generateUrgencyPost,
    educational: generateEducationalPost,
    testimonial: generateTestimonialPost,
};

// ============================================================
// CHANNEL BROADCASTER — runs 3x per hour
// ============================================================
async function runChannelPost() {
    const type = nextContentType();
    const generator = GENERATORS[type];

    console.log(`📢 Broadcasting [${type}] to Telegram channel...`);

    try {
        const completion = await generator();
        let text = completion.choices[0]?.message?.content?.trim() || '';

        // Strip any markdown fences the AI sneaks in
        text = text.replace(/```html?/gi, '').replace(/```/g, '').trim();

        if (!text) {
            console.warn('⚠️  Empty post generated — skipping.');
            return;
        }

        const result = await sendToChannel(text);
        if (result?.ok) {
            addToHistory(type, text.replace(/<[^>]*>/g, '')); // strip HTML for history preview
            console.log(`✅ Channel post sent [${type}]`);
        } else {
            console.error(`❌ Channel post failed [${type}]:`, result?.description);
        }

    } catch (err) {
        console.error(`❌ Channel post error [${type}]:`, err.message);
    }
}

// ============================================================
// ADMIN BOT — answers your questions about the business
// ============================================================

// Track last update_id so we don't process the same message twice
let lastUpdateId = 0;

// Live business data for admin context
async function fetchLiveContext() {
    try {
        const [users, subs, payments, online] = await Promise.allSettled([
            supabase.from('profiles').select('id', { count: 'exact', head: true }),
            supabase.from('activations').select('code_type', { count: 'exact', head: false }),
            supabase.from('payments').select('amount').eq('status', 'success')
                .gte('created_at', new Date(new Date().setHours(0, 0, 0, 0)).toISOString()),
            Promise.resolve(global.activeSessions?.size || 0)
        ]);

        const subsData = subs.status === 'fulfilled' ? subs.value.data : [];
        const paymentsData = payments.status === 'fulfilled' ? payments.value.data : [];
        const totalRevToday = paymentsData.reduce((s, p) => s + Number(p.amount || 0), 0);
        const planBreakdown = (subsData || []).reduce((acc, s) => {
            acc[s.code_type] = (acc[s.code_type] || 0) + 1; return acc;
        }, {});
        
        const planStr = Object.entries(planBreakdown).map(([k, v]) => `${(k || 'UNKNOWN').replace(/_/g, ' ')}: ${v}`).join(', ') || 'None';

        return {
            totalUsers: users.status === 'fulfilled' ? (users.value.count || 0) : '?',
            activeSubscribers: (subsData || []).length,
            planBreakdown: planStr,
            revenueToday: `$${totalRevToday.toFixed(2)}`,
            paymentsToday: paymentsData.length,
            onlineNow: online,
            postsToday: postHistory.length,
            lastPostType: postHistory[postHistory.length - 1]?.type || 'none',
        };
    } catch (_) {
        return { error: 'Could not fetch live data' };
    }
}

const ADMIN_SYSTEM_PROMPT = `You are ARIA, the AviSignals AI Business Assistant speaking directly to the founder/CEO via Telegram.

BUSINESS OVERVIEW:
- AviSignals: AI-powered Aviator game prediction platform, based in Kenya
- Free tier: 1 free daily prediction code (30-min session)
- Paid tier: $75 = 24-hour continuous access
- Payment: M-Pesa + card via Paystack
- Target market: Global, Whole World
- Channels: Telegram channel, WhatsApp, website (avisignals.com)

YOUR ROLE:
- Answer any question the founder asks about the business
- Give live stats when asked (I will inject them into your context)
- Suggest growth ideas, marketing tactics, and fixes
- Help draft messages, posts, or emails when asked
- Flag anything that needs urgent attention
- Be direct, concise, and actionable — this is a busy founder

TONE: Like a sharp, loyal COO speaking to the CEO. Confident, data-driven, no fluff.
FORMAT: Use Telegram Markdown — *bold*, _italic_, bullet points with -`;

async function handleAdminMessage(message) {
    const text = message.text || '';
    const chatId = message.chat.id;
    const fromId = message.from?.id;

    // Security — only respond to the configured admin chat
    if (String(chatId) !== String(ADMIN_CHAT) && String(fromId) !== String(ADMIN_CHAT)) {
        console.log(`⚠️  Ignored message from unauthorized chat: ${chatId}`);
        return;
    }

    console.log(`📩 Admin message received: "${text.slice(0, 60)}"`);

    // Handle commands
    if (text.startsWith('/status') || text.toLowerCase().includes('status')) {
        const ctx = await fetchLiveContext();
        const statusMsg = `📊 *Live AviSignals Status*\n\n` +
            `👥 Total users: *${ctx.totalUsers}*\n` +
            `✅ Active subscribers: *${ctx.activeSubscribers}*\n` +
            `📦 Plan breakdown: ${ctx.planBreakdown}\n` +
            `💰 Revenue today: *${ctx.revenueToday}* (${ctx.paymentsToday} payments)\n` +
            `🟢 Online now: *${ctx.onlineNow}*\n` +
            `📢 Channel posts today: *${ctx.postsToday}* (last: ${ctx.lastPostType})\n` +
            `🕐 As of: ${new Date().toLocaleTimeString('en-KE', { timeZone: 'Africa/Nairobi' })}`;

        await telegramRequest('sendMessage', {
            chat_id: chatId,
            text: statusMsg,
            parse_mode: 'Markdown'
        });
        return;
    }

    if (text.startsWith('/post') || text.toLowerCase() === 'post now') {
        await telegramRequest('sendMessage', {
            chat_id: chatId,
            text: '📢 Triggering a channel post now...',
            parse_mode: 'Markdown'
        });
        await runChannelPost();
        await telegramRequest('sendMessage', {
            chat_id: chatId,
            text: '✅ Post sent to channel.',
            parse_mode: 'Markdown'
        });
        return;
    }

    if (text.startsWith('/help')) {
        const helpMsg = `🤖 *ARIA — AviSignals Business Assistant*\n\n` +
            `Here's what you can ask me:\n\n` +
            `- *Any business question* — growth, marketing, conversions\n` +
            `- *"status"* or */status* — live business metrics\n` +
            `- *"post now"* or */post* — trigger a channel broadcast immediately\n` +
            `- *"write a post about X"* — draft a channel post\n` +
            `- *"write an email about X"* — draft a subscriber email\n` +
            `- *"how many subscribers"* — subscriber stats\n` +
            `- *"what should I do today"* — daily priorities\n\n` +
            `Or just ask me anything in plain English. I have live access to your business data.`;

        await telegramRequest('sendMessage', {
            chat_id: chatId,
            text: helpMsg,
            parse_mode: 'Markdown'
        });
        return;
    }

    // For everything else — pass to AI with live context injected
    try {
        const ctx = await fetchLiveContext();

        const contextBlock = `\nLIVE BUSINESS DATA (as of ${new Date().toLocaleTimeString('en-KE', { timeZone: 'Africa/Nairobi' })}):\n` +
            Object.entries(ctx).map(([k, v]) => `- ${k}: ${v}`).join('\n');

        const completion = await groq.chat.completions.create({
            messages: [
                { role: 'system', content: ADMIN_SYSTEM_PROMPT + contextBlock },
                { role: 'user', content: text }
            ],
            model: 'llama-3.3-70b-versatile',
            temperature: 0.6,
            max_tokens: 600
        });

        const reply = completion.choices[0]?.message?.content?.trim()
            || 'Sorry, I had trouble generating a response. Try again.';

        await telegramRequest('sendMessage', {
            chat_id: chatId,
            text: reply,
            parse_mode: 'Markdown'
        });

    } catch (err) {
        console.error('❌ Admin bot AI error:', err.message);
        await telegramRequest('sendMessage', {
            chat_id: chatId,
            text: '⚠️ I had an error processing that. Try again in a moment.',
            parse_mode: 'Markdown'
        });
    }
}

// ─── Long polling loop ────────────────────────────────────────
let pollingActive = false;

async function pollForAdminMessages() {
    if (!BOT_TOKEN || !ADMIN_CHAT) return;
    if (pollingActive) return;
    pollingActive = true;

    console.log('👂 Admin bot polling started...');

    const poll = async () => {
        try {
            const res = await telegramRequest('getUpdates', {
                offset: lastUpdateId + 1,
                timeout: 30,   // long poll — waits up to 30s for a message
                allowed_updates: ['message']
            });

            if (res?.ok && res.result?.length) {
                for (const update of res.result) {
                    lastUpdateId = update.update_id;
                    if (update.message) {
                        await handleAdminMessage(update.message);
                    }
                }
            }
        } catch (err) {
            console.error('❌ Polling error:', err.message);
            await new Promise(r => setTimeout(r, 5000)); // back off on error
        }

        if (pollingActive) {
            setImmediate(poll); // tight loop — processes messages as fast as they arrive
        }
    };

    poll();
}

function stopPolling() {
    pollingActive = false;
    console.log('🛑 Admin bot polling stopped.');
}

// ============================================================
// STARTUP
// ============================================================
function startTelegramAgent() {
    console.log('🚀 AviSignals Telegram Agent v2 — Initializing...');

    // 3 posts per hour — at :00, :20, and :40 past each hour
    // Covers 6am to 11pm Nairobi time (adjust if VPS is not UTC+3)
    cron.schedule('0 6-23 * * *', runChannelPost);  // on the hour
    cron.schedule('20 6-23 * * *', runChannelPost);  // 20 past
    cron.schedule('40 6-23 * * *', runChannelPost);  // 40 past

    // Start admin bot polling
    pollForAdminMessages();

    console.log('✅ Telegram Agent ready:');
    console.log('   📢 Channel broadcast — 3x per hour (:00, :20, :40), 6am–11pm');
    console.log('   👂 Admin bot polling  — always on, responds to your messages');
    console.log(`   💬 Admin chat ID      — ${ADMIN_CHAT || 'NOT SET (set TELEGRAM_CHAT_ID)'}`);
    console.log(`   📣 Channel            — ${CHANNEL_ID}`);
}

module.exports = {
    startTelegramAgent,
    runChannelPost,
    sendToAdmin,
    sendToChannel,
    stopPolling
};
